package main

import (
	"bufio"
	"os"
	"strconv"
	"strings"
)

func processa(vet []int, i int, str []string) []string {
	i++
	if len(vet) == 1 {
		return str
	}

	str += append(str, strconv.Atoi(vet[i]))
	return processa(vet, i, str)
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	if !scanner.Scan() {
		return
	}
	line := scanner.Text()
	parts := strings.Fields(line)
	vet := []int{}
	for _, part := range parts {
		if value, err := strconv.Atoi(part); err == nil {
			vet = append(vet, value)
		}
	}
	processa(vet)
}

func soma(vet []int, i int, str string) string {
	i++
	if i == len(vet)-1 {
		return "[ " + str + "]"
	}

	if i < len(vet)-1 {
		num := vet[i] + vet[i+1]
		str += strconv.Itoa(num) + " "
	}

	return soma(vet, i, str)
}
